-- 1) Backup snapshot of current WC2026 fixtures
DROP TABLE IF EXISTS public.matches_wc2026_backup_20260605;
CREATE TABLE public.matches_wc2026_backup_20260605 AS
  SELECT * FROM public.matches WHERE competition = 'FIFA World Cup 2026';
GRANT SELECT ON public.matches_wc2026_backup_20260605 TO authenticated;
GRANT ALL ON public.matches_wc2026_backup_20260605 TO service_role;
ALTER TABLE public.matches_wc2026_backup_20260605 ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Admins read wc2026 backup" ON public.matches_wc2026_backup_20260605
  FOR SELECT TO authenticated USING (public.has_role(auth.uid(), 'admin'::app_role));

-- 2) Disable the official-fixture lock trigger for this migration
ALTER TABLE public.matches DISABLE TRIGGER wc_lock_official_fixture_fields_trg;

